import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { authAPI } from '../api/client';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(localStorage.getItem('isp_token'));
  const [loading, setLoading] = useState(true);

  // On mount: restore user from token if valid
  useEffect(() => {
    const restoreSession = async () => {
      const savedToken = localStorage.getItem('isp_token');
      if (!savedToken) { setLoading(false); return; }

      try {
        const res = await authAPI.getMe();
        if (res.data.success) setUser(res.data.data);
        else logout();
      } catch {
        logout();
      } finally {
        setLoading(false);
      }
    };
    restoreSession();
  }, []);

  const login = useCallback(async (email, password) => {
    const res = await authAPI.login({ email, password });
    if (res.data.success) {
      const { token: newToken, user: userData } = res.data.data;
      localStorage.setItem('isp_token', newToken);
      localStorage.setItem('isp_user', JSON.stringify(userData));
      setToken(newToken);
      setUser(userData);
      return { success: true };
    }
    return { success: false, message: res.data.message };
  }, []);

  const register = useCallback(async (name, email, password, college) => {
    const res = await authAPI.register({ name, email, password, college });
    if (res.data.success) {
      const { token: newToken, user: userData } = res.data.data;
      localStorage.setItem('isp_token', newToken);
      localStorage.setItem('isp_user', JSON.stringify(userData));
      setToken(newToken);
      setUser(userData);
      return { success: true };
    }
    return { success: false, message: res.data.message };
  }, []);

  const logout = useCallback(() => {
    localStorage.removeItem('isp_token');
    localStorage.removeItem('isp_user');
    setToken(null);
    setUser(null);
  }, []);

  return (
    <AuthContext.Provider value={{ user, token, loading, login, register, logout, isAuthenticated: !!token }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used inside AuthProvider');
  return ctx;
};
